/* QueryX offline HTMX-compatible fragment polling runtime. No upload interception. */
(()=>{const timers=new WeakMap();function seconds(v){const m=/every\s+([\d.]+)s/i.exec(v||"");return m?Math.max(250,Number(m[1])*1000):0}async function swap(el){if(!document.contains(el))return;try{const r=await fetch(el.getAttribute("hx-get"),{headers:{"HX-Request":"true"},credentials:"same-origin"});if(!r.ok)return;const h=await r.text();if((el.getAttribute("hx-swap")||"innerHTML")==="outerHTML"){const t=document.createElement("template");t.innerHTML=h.trim();const n=t.content.firstElementChild;if(n){el.replaceWith(n);scan(n)}}else{el.innerHTML=h;scan(el)}}catch(_){}}function scan(root=document){const nodes=[];if(root.matches&&root.matches("[hx-get][hx-trigger]"))nodes.push(root);root.querySelectorAll?.("[hx-get][hx-trigger]").forEach(n=>nodes.push(n));nodes.forEach(el=>{if(timers.has(el))return;const ms=seconds(el.getAttribute("hx-trigger"));if(ms)timers.set(el,setInterval(()=>swap(el),ms))})}window.htmx={process:scan};document.addEventListener("DOMContentLoaded",()=>scan())})();
